<div class="d-flex justify-content-between align-items-center mb-3 mobile-stack"><div><h1 class="page-title h3 mb-1">Satuan</h1><div class="text-muted">Kelola satuan untuk produk dan transaksi.</div></div><a class="btn btn-primary" href="<?= e(url('index.php?page=referensi-satuan-create')) ?>">Tambah Satuan</a></div>
